"use client"

import * as React from "react"
import { Progress as ProgressPrimitive } from "@ark-ui/react/progress"

import { cn } from "@/registry/ark-vega/lib/utils"

function Progress({
  className,
  value,
  ...props
}: React.ComponentProps<typeof ProgressPrimitive.Root>) {
  return (
    <ProgressPrimitive.Root
      data-slot="progress"
      className={cn("h-1.5 rounded-full bg-muted", className)}
      value={value}
      {...props}
    >
      <ProgressPrimitive.Track className="h-1.5 rounded-full bg-muted">
        <ProgressPrimitive.Range className="" />
      </ProgressPrimitive.Track>
    </ProgressPrimitive.Root>
  )
}

export { Progress }
